// Extraer la ruta de la carpeta del evento
const event = $input.first().json;
const folderPath = event.path;

// Solo procesar si es una carpeta (no archivos sueltos)
if (!event.isDirectory) {
  return [];
}

console.log('Nueva carpeta detectada:', folderPath);
return [{ json: { folderPath, topic: folderPath.split('/').pop() } }];

const output = $input.first().json;
const success = !output.stderr || output.exitCode === 0;

if (success) {
  console.log('✅ Post generado exitosamente');
  return [{ json: { status: 'ok', output: output.stdout } }];
} else {
  console.error('❌ Error:', output.stderr);
  return [{ json: { status: 'error', error: output.stderr } }];
}
